const express = require('express');
const helmet = require('helmet');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Set secure HTTP headers (X-Content-Type-Options, CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a strict size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Disable the X-Powered-By header to avoid fingerprinting
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const limit = parseInt(req.query.limit, 10);
  const offset = parseInt(req.query.offset, 10);

  if (req.query.limit !== undefined && (isNaN(limit) || limit < 1 || limit > 100)) {
    return res.status(400).json({ error: 'limit must be an integer between 1 and 100' });
  }
  if (req.query.offset !== undefined && (isNaN(offset) || offset < 0)) {
    return res.status(400).json({ error: 'offset must be a non-negative integer' });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  const start = offset || 0;
  const end = limit ? start + limit : users.length;

  res.json(users.slice(start, end));
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
